# Step 1: Require authentication for all shelter location endpoints
# Flask example:
from functools import wraps
from flask import g, jsonify

def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not g.current_user or not g.current_user.is_authenticated:
            return jsonify({"error": "Authentication required"}), 401
        return f(*args, **kwargs)
    return decorated

@app.route('/api/shelters/nearby')
@require_auth
def get_nearby_shelters():
    # Only return approximate area, never exact coordinates
    return jsonify(get_shelters_approximate_area())

